1	"use client";
2	
3	import { BackButton } from "@/shared/ui/back-button-new/back-button";
4	import { CreateTicketForm } from "@/widgets/create-ticket-form";
5	import { useRouter } from "next/navigation";
6	
7	export default function CreateTicketPage() {
